## Step 4 — Create the Controller

New file: `src/main/java/com/bukuwarung/fsbnplservice/controller/LendingTwoFAController.java`

```java
package com.bukuwarung.fsbnplservice.controller;

import com.bukuwarung.fsbnplservice.config.AuthConstant;
import com.bukuwarung.fsbnplservice.config.FirebaseTokenService;
import com.bukuwarung.fsbnplservice.dto.ResponseDto;
import com.bukuwarung.fsbnplservice.dto.twofa.*;
import com.bukuwarung.fsbnplservice.entity.MerchantDataEntity;
import com.bukuwarung.fsbnplservice.repository.MerchantDataRepository;
import com.bukuwarung.fsbnplservice.service.TwoFactorAuthService;
import javax.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.http.HttpHeaders;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/merchant/lending/twofa")
@RequiredArgsConstructor
@Slf4j
public class LendingTwoFAController {

  private final TwoFactorAuthService twoFactorAuthService;
  private final FirebaseTokenService firebaseTokenService;
  private final MerchantDataRepository merchantDataRepository;

  @GetMapping("/pin/status")
  public ResponseEntity<ResponseDto<TwoFAPinStatusResponseDto>> getPinStatus(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    boolean hasPin = twoFactorAuthService.hasLendingPin(userId);
    return ResponseEntity.ok(ResponseDto.success("PIN status retrieved", TwoFAPinStatusResponseDto.builder().hasPin(hasPin).build()));
  }

  @PostMapping("/otp/send")
  public ResponseEntity<ResponseDto<Void>> sendOtp(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken,
      @RequestBody TwoFASendOtpRequestDto request) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    String email = request.getEmail();
    String phone = request.getPhone();
    if (StringUtils.isBlank(email) || StringUtils.isBlank(phone)) {
      MerchantDataEntity merchant = merchantDataRepository.findAllByUserIdAndProductType(
          java.util.List.of(userId), "BNPL").stream().findFirst().orElse(null);
      if (merchant != null) {
        if (StringUtils.isBlank(email)) email = merchant.getEmail();
        if (StringUtils.isBlank(phone)) phone = merchant.getPhoneNumber();
      }
    }
    twoFactorAuthService.sendOtpForPinSetup(userId, email, phone, request.getMethod());
    return ResponseEntity.ok(ResponseDto.success("OTP sent", null));
  }

  @PostMapping("/otp/verify")
  public ResponseEntity<ResponseDto<TwoFAVerifyOtpResponseDto>> verifyOtp(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken,
      @RequestBody TwoFAVerifyOtpRequestDto request) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    TwoFAVerifyOtpResponseDto result = twoFactorAuthService.verifyOtpForPinSetup(userId, request.getOtp(), request.getEmail());
    return ResponseEntity.ok(ResponseDto.success("OTP verified", result));
  }

  @PostMapping("/pin/setup")
  public ResponseEntity<ResponseDto<TwoFAVerifyPinResponseDto>> setupPin(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken,
      @Valid @RequestBody TwoFASetupPinRequestDto request) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    TwoFAVerifyPinResponseDto result = twoFactorAuthService.setupLendingPin(userId, request.getPin(), request.getDeviceId());
    return ResponseEntity.ok(ResponseDto.success("PIN set up successfully", result));
  }

  @PostMapping("/pin/verify")
  public ResponseEntity<ResponseDto<TwoFAVerifyPinResponseDto>> verifyPin(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken,
      @RequestBody TwoFAVerifyPinRequestDto request) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    TwoFAVerifyPinResponseDto result = twoFactorAuthService.verifyLendingPin(userId, request.getPin(), request.getDeviceId());
    return ResponseEntity.ok(ResponseDto.success("PIN verified", result));
  }

  @PutMapping("/pin/update")
  public ResponseEntity<ResponseDto<TwoFAVerifyPinResponseDto>> updatePin(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken,
      @Valid @RequestBody TwoFAUpdatePinRequestDto request) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    TwoFAVerifyPinResponseDto result = twoFactorAuthService.updateLendingPin(userId, request.getOldPin(), request.getNewPin(), request.getDeviceId());
    return ResponseEntity.ok(ResponseDto.success("PIN updated", result));
  }

  @PutMapping("/pin/forgot")
  public ResponseEntity<ResponseDto<Void>> forgotPin(
      @RequestHeader(value = HttpHeaders.AUTHORIZATION) String firebaseAuthToken,
      @Valid @RequestBody TwoFAForgotPinRequestDto request) {
    String userId = firebaseTokenService.getClaimValueFromFirebaseToken(firebaseAuthToken, AuthConstant.USER_ID_CLAIM);
    twoFactorAuthService.resetLendingPin(userId, request.getNewPin(), request.getDeviceId());
    return ResponseEntity.ok(ResponseDto.success("PIN reset successfully", null));
  }
}
```

**Note on service method mapping:**
- `forgotPin` endpoint → calls `twoFactorAuthService.resetLendingPin(userId, newPin, deviceId)` (the existing method, AC used `forgotLendingPin` as alias)
- `updatePin` endpoint → calls `twoFactorAuthService.updateLendingPin(userId, oldPin, newPin, deviceId)` (AC used `updateLendingPin(request, userId)` as shorthand)

